import React, { useState, useEffect } from 'react';
import './AddPurchase.css';

const AddPurchase = ({ handleAdd, locations }) => {
  const initialPurchaseState = {
    location: '', // Initialize location to an empty string
    materialid: '',
    quantity: '',
    price: '',
    vendor: '',
  };

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);
  const [defaultPrice, setDefaultPrice] = useState('');
  const [defaultVendor, setDefaultVendor] = useState('');

  useEffect(() => {
    // Fetch data from material_changes based on the provided materialid
    if (newPurchase.materialid) {
      fetch(`http://localhost:8081/MaterialChangesAPI/${newPurchase.materialid}`)
        .then((response) => response.json())
        .then((data) => {
          if (data && data.price) {
            setDefaultPrice(data.price);
            setNewPurchase((prevPurchase) => ({
              ...prevPurchase,
              price: data.price,
            }));
          }
          if (data && data.vendor) {
            setDefaultVendor(data.vendor);
            setNewPurchase((prevPurchase) => ({
              ...prevPurchase,
              vendor: data.vendor,
            }));
          }
        })
        .catch((error) => {
          console.error('Error fetching material changes:', error);
        });
    }
  }, [newPurchase.materialid]);



  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase({
      ...newPurchase,
      [name]: value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    handleAdd(newPurchase);
    setNewPurchase(initialPurchaseState); // Clear the form after adding a purchase
  };

  return (
    <form onSubmit={handleSubmit} class='add-purchase-form'>
      <div>
        <label>Location:</label>
        <select name="location" value={newPurchase.location} onChange={handleChange}>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={newPurchase.materialid} onChange={handleChange} />
      </div>
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={newPurchase.quantity} onChange={handleChange} />
      </div>
      <div>
        <label>Price:</label>
        <input
          type="text"
          name="price"
          value={newPurchase.price || defaultPrice} // Use defaultPrice as the default value if newPurchase.price is empty
          onChange={handleChange}
        />
      </div>
      <div>
        <label>Vendor:</label>
        <input
          type="text"
          name="vendor"
          value={newPurchase.vendor || defaultVendor} // Use defaultVendor as the default value if newPurchase.vendor is empty
          onChange={handleChange}
        />
      </div>
      <button type="submit" class="add_purchase_btn">Add Purchase</button>
    </form>
  );
};

export default AddPurchase;
